      \amp =  \frac{(4 y+7)(y-1)}{30 y ^{4} (7 y-2)} \cdot \frac{5 y ^{4} (2 - 7 y)}{(4 y+7)(4 y - 7)} \\
      \amp = \frac{{\left(4y+7\right)\mathopen{}\left(y-1\right)}}{{30y^{4}\mathopen{}\left(7y-2\right)}} \cdot \frac{{-5y^{4}\mathopen{}\left(7y-2\right)}}{{\left(4y+7\right)\mathopen{}\left(4y-7\right)}} \\
      \amp = {-\frac{y-1}{6\mathopen{}\left(4y-7\right)}, y\ne -1.75\hbox{ and }y\ne 0.285714\hbox{ and }y\ne 0}
